ST.xhtml:
reset();

lMessageCount := 0;

lPostTimer.Enable := TRUE;
lPostTimer.Period := T#5S;
lPostTimer.initialize();

lSuccess := FALSE;
lProceed := FALSE;
lFinished := FALSE;
lStarted := FALSE;

SUPER^.initialize();

FOR i:=1 TO lSequenceCount DO
	lSequence[i]^.initialize();
END_FOR

IF ((NOT(Enabled)) OR (NOT(Running))) THEN
	RETURN;
END_IF

SUPER^.operator();

lSequence[lSequenceIndex]^.operator();

IF (lSequence[lSequenceIndex]^.Finished) THEN
	IF (lSequence[lSequenceIndex]^.Proceed) THEN
		b:= lSequence[lSequenceIndex]^.Success;

		lSequenceIndex := lSequenceIndex + 1;
		IF (lSequenceIndex>lSequenceCount) THEN
			lSuccess := b;
			lFinished := TRUE;
			finish();
		ELSE
			lSequence[lSequenceIndex]^.start();	
		END_IF
	ELSE
		lSuccess := FALSE;
		lFinished := TRUE;
		finish();
	END_IF
END_IF

IF (lSequenceCount>32) THEN
	registerMessage := 0;
	RETURN;
END_IF

lSequenceCount := lSequenceCount + 1;
lSequence[lSequenceCount] := message;

SUPER^.reset();

lSequenceIndex := 0;

FOR i:=1 TO lSequenceCount DO
	lSequence[i]^.reset();
END_FOR

SUPER^.reset();

IF (lSequenceCount=0) THEN
	lSequenceIndex := 0;
	RETURN;
END_IF

lSequenceIndex := 1;

lSequence[lSequenceIndex]^.start();

lRising := (lCountPrev=0) AND (lCount>0);
lFalling := (lCountPrev>0) AND (lCount=0);
lHigh := (lCount>0);

IF (lRising) THEN
	lUnique := lUnique + 1;
END_IF

lCountPrev := lCount;
lCount := 0;

lCount := lCountPrev := 0;
lUnique := 0;
lRising := lFalling := lHigh := FALSE;

lCount := lCountPrev := 0;
lUnique := 0;
lRising := lFalling := lHigh := FALSE;

lng :=INT_TO_UINT(LEN(str1));

IF (lng<>INT_TO_UINT(LEN(str2))) THEN
	strcmp := FALSE;
	RETURN;
END_IF

FOR i:=0 TO lng DO
	IF (str1[i]<>str2[i]) THEN
		strcmp := FALSE;
		RETURN;
	END_IF
END_FOR

strcmp := TRUE;

IF (NOT(lExpired)) THEN
	lUnexpiredMax := MAX(lUnexpiredMax,lTimer.ET);
END_IF

SUPER^.reset();
